(("undefined"!=typeof globalThis?globalThis:self)["makoChunk_@ant-design/x"]=("undefined"!=typeof globalThis?globalThis:self)["makoChunk_@ant-design/x"]||[]).push([["77fa7de0"],{"77fa7de0":function(e,a,n){"use strict";n.d(a,"__esModule",{value:!0}),n.d(a,"texts",{enumerable:!0,get:function(){return t;}}),n("c1148f3a");let t=[{value:"@ant-design/x-card",paraId:0,tocIndex:0},{value:" is a dynamic card rendering component based on the ",paraId:0,tocIndex:0},{value:"A2UI protocol",paraId:0,tocIndex:0},{value:", enabling AI Agents to dynamically build and render interactive UIs through structured JSON message streams.",paraId:0,tocIndex:0},{value:"A2UI (Agent-to-User Interface) is an open protocol that allows AI Agents to describe interaction intent through declarative JSON message sequences, which the frontend runtime dynamically renders into native UI components.",paraId:1,tocIndex:1},{value:"A2UI is built on three core ideas:",paraId:2,tocIndex:2},{value:"Streaming Messages",paraId:3,tocIndex:2},{value:": UI updates flow from the Agent to the client as a sequence of JSON messages",paraId:3,tocIndex:2},{value:"Declarative Components",paraId:3,tocIndex:2},{value:": UI is described as data, not code",paraId:3,tocIndex:2},{value:"Data Binding",paraId:3,tocIndex:2},{value:": UI structure is decoupled from application state, enabling reactive updates",paraId:3,tocIndex:2},{value:"Unlike traditional approaches where AI generates HTML directly, A2UI uses structured data streams with significant advantages:",paraId:4,tocIndex:3},{value:"Feature",paraId:5,tocIndex:3},{value:"A2UI",paraId:5,tocIndex:3},{value:"AI-generated HTML",paraId:5,tocIndex:3},{value:"Security",paraId:5,tocIndex:3},{value:"Only uses predefined component catalog, no code execution risk",paraId:5,tocIndex:3},{value:"May contain malicious scripts, injection risk",paraId:5,tocIndex:3},{value:"Cross-platform",paraId:5,tocIndex:3},{value:"One data structure auto-adapts to Web, mobile, and other native components",paraId:5,tocIndex:3},{value:"HTML requires extra adaptation per platform",paraId:5,tocIndex:3},{value:"Streaming Rendering",paraId:5,tocIndex:3},{value:"Supports progressive rendering for smooth UX",paraId:5,tocIndex:3},{value:"Requires complete response before rendering",paraId:5,tocIndex:3},{value:"LLM-friendly",paraId:5,tocIndex:3},{value:"Flat JSON structure supports incremental generation, reduces AI burden",paraId:5,tocIndex:3},{value:"Requires generating full HTML structure, prone to syntax errors",paraId:5,tocIndex:3},{value:"Maintenance",paraId:5,tocIndex:3},{value:"Components managed centrally, updates only require client library changes",paraId:5,tocIndex:3},{value:"Each HTML interface needs individual debugging",paraId:5,tocIndex:3},{value:"A2UI follows the unidirectional data flow principle, ensuring predictable data direction:",paraId:6,tocIndex:4},{value:"Agent (LLM) \u2192 A2UI Generator \u2192 Transport (SSE/WebSocket/A2A)\n                    \u2193\nClient (Stream Reader) \u2192 Message Parser \u2192 Renderer \u2192 Native UI\n",paraId:7,tocIndex:4},{value:"Using a restaurant booking as an example:",paraId:8,tocIndex:5},{value:'sequenceDiagram\n    participant User\n    participant Client\n    participant Agent\n\n    User->>Client: "Book a table for 2 tomorrow at 7pm"\n    Client->>Agent: Send user request\n\n    Note over Agent: 1. Create UI container\n    Agent->>Client: createSurface { surfaceId: "booking" }\n\n    Note over Agent: 2. Define UI structure\n    Agent->>Client: updateComponents { components: [...] }\n\n    Note over Agent: 3. Populate initial data\n    Agent->>Client: updateDataModel { datetime: "2025-12-16T19:00", guests: 2 }\n\n    Note over Client: 4. Render booking form\n    Client->>User: Show date picker and guest count input\n\n    User->>Client: Change guest count to 3\n    Note over Client: Auto-updates /reservation/guests\n\n    User->>Client: Click "Confirm" button\n    Client->>Agent: userAction { name: "confirm", context: { guests: 3 } }\n\n    Note over Agent: 5. Handle user action\n    Agent->>Client: deleteSurface { surfaceId: "booking" }\n    Agent->>Client: Create success confirmation UI\n',paraId:9,tocIndex:5},{value:"@ant-design/x-card",paraId:10,tocIndex:6},{value:" supports both v0.8 and v0.9 of the A2UI protocol. Understanding the differences helps you choose the right version and migrate if needed.",paraId:10,tocIndex:6},{value:"Feature",paraId:11,tocIndex:7},{value:"v0.8",paraId:11,tocIndex:7},{value:"v0.9",paraId:11,tocIndex:7},{value:"Version field",paraId:11,tocIndex:7},{value:"No explicit version field",paraId:11,tocIndex:7},{value:"Explicit ",paraId:11,tocIndex:7},{value:"version: 'v0.9'",paraId:11,tocIndex:7},{value:" field",paraId:11,tocIndex:7},{value:"Surface creation",paraId:11,tocIndex:7},{value:"Implicit (auto-created on first updateComponents)",paraId:11,tocIndex:7},{value:"Explicit ",paraId:11,tocIndex:7},{value:"createSurface",paraId:11,tocIndex:7},{value:" command",paraId:11,tocIndex:7},{value:"Data model update",paraId:11,tocIndex:7},{value:"Uses ",paraId:11,tocIndex:7},{value:"contents",paraId:11,tocIndex:7},{value:" array",paraId:11,tocIndex:7},{value:"Uses ",paraId:11,tocIndex:7},{value:"path",paraId:11,tocIndex:7},{value:" and ",paraId:11,tocIndex:7},{value:"value",paraId:11,tocIndex:7},{value:" fields",paraId:11,tocIndex:7},{value:"Component definition",paraId:11,tocIndex:7},{value:"More complex nested structure",paraId:11,tocIndex:7},{value:"Simpler flat structure",paraId:11,tocIndex:7},{value:"Recommendation",paraId:11,tocIndex:7},{value:"Deprecated, compatibility only",paraId:11,tocIndex:7},{value:"Recommended",paraId:11,tocIndex:7},{value:"v0.8 uses implicit Surface creation \u2014 a Surface is automatically created when the Agent sends the first ",paraId:12,tocIndex:8},{value:"updateComponents",paraId:12,tocIndex:8},{value:":",paraId:12,tocIndex:8},{value:"// v0.8 has no explicit version field\n{\n  updateComponents: {\n    surfaceId: 'booking',\n    catalogId: 'https://example.com/catalogs/booking/v1/catalog.json',\n    components: [\n      {\n        id: 'root',\n        component: 'Column',\n        children: ['header', 'content']\n      }\n    ]\n  }\n}\n",paraId:13,tocIndex:8},{value:"Data model updates",paraId:14,tocIndex:8},{value:" use the ",paraId:14,tocIndex:8},{value:"contents",paraId:14,tocIndex:8},{value:" array:",paraId:14,tocIndex:8},{value:"{\n  updateDataModel: {\n    surfaceId: 'booking',\n    contents: [\n      {\n        op: 'replace',\n        path: '/reservation/guests',\n        value: 3\n      }\n    ]\n  }\n}\n",paraId:15,tocIndex:8},{value:"v0.9 introduces explicit version identification and a Surface creation command, making the protocol clearer and more controllable:",paraId:16,tocIndex:9},{value:"// Explicitly create Surface\n{\n  version: 'v0.9',\n  createSurface: {\n    surfaceId: 'booking',\n    catalogId: 'https://example.com/catalogs/booking/v1/catalog.json'\n  }\n}\n\n// Update components\n{\n  version: 'v0.9',\n  updateComponents: {\n    surfaceId: 'booking',\n    components: [\n      {\n        id: 'root',\n        component: 'Column',\n        children: ['header', 'content']\n      }\n    ]\n  }\n}\n",paraId:17,tocIndex:9},{value:"Data model updates",paraId:18,tocIndex:9},{value:" use the more intuitive ",paraId:18,tocIndex:9},{value:"path",paraId:18,tocIndex:9},{value:" and ",paraId:18,tocIndex:9},{value:"value",paraId:18,tocIndex:9},{value:" fields:",paraId:18,tocIndex:9},{value:"{\n  version: 'v0.9',\n  updateDataModel: {\n    surfaceId: 'booking',\n    path: '/reservation/guests',\n    value: 3\n  }\n}\n",paraId:19,tocIndex:9},{value:"If you are using v0.8, follow these steps to migrate to v0.9:",paraId:20,tocIndex:10},{value:"Add ",paraId:21,tocIndex:11},{value:"version: 'v0.9'",paraId:21,tocIndex:11},{value:" to all messages:",paraId:21,tocIndex:11},{value:"// v0.8\n{ updateComponents: { ... } }\n\n// v0.9\n{ version: 'v0.9', updateComponents: { ... } }\n",paraId:22,tocIndex:11},{value:"Send ",paraId:23,tocIndex:12},{value:"createSurface",paraId:23,tocIndex:12},{value:" before ",paraId:23,tocIndex:12},{value:"updateComponents",paraId:23,tocIndex:12},{value:":",paraId:23,tocIndex:12},{value:"// v0.8: implicit creation\n{ updateComponents: { surfaceId: 'booking', catalogId: '...', components: [...] } }\n\n// v0.9: explicit creation\n[\n  { version: 'v0.9', createSurface: { surfaceId: 'booking', catalogId: '...' } },\n  { version: 'v0.9', updateComponents: { surfaceId: 'booking', components: [...] } }\n]\n",paraId:24,tocIndex:12},{value:"Replace the ",paraId:25,tocIndex:13},{value:"contents",paraId:25,tocIndex:13},{value:" array with ",paraId:25,tocIndex:13},{value:"path",paraId:25,tocIndex:13},{value:" + ",paraId:25,tocIndex:13},{value:"value",paraId:25,tocIndex:13},{value:":",paraId:25,tocIndex:13},{value:"// v0.8\n{\n  updateDataModel: {\n    surfaceId: 'booking',\n    contents: [\n      { op: 'replace', path: '/guests', value: 3 }\n    ]\n  }\n}\n\n// v0.9\n{\n  version: 'v0.9',\n  updateDataModel: {\n    surfaceId: 'booking',\n    path: '/guests',\n    value: 3\n  }\n}\n",paraId:26,tocIndex:13},{value:"v0.9 supports updating entire objects, reducing message count:",paraId:27,tocIndex:14},{value:"// v0.8: multiple messages required\n[\n  { updateDataModel: { surfaceId: 'booking', contents: [{ op: 'add', path: '/date', value: '2025-12-16' }] } },\n  { updateDataModel: { surfaceId: 'booking', contents: [{ op: 'add', path: '/guests', value: 2 }] } }\n]\n\n// v0.9: one message is enough\n{\n  version: 'v0.9',\n  updateDataModel: {\n    surfaceId: 'booking',\n    path: '/reservation',\n    value: { date: '2025-12-16', guests: 2 }\n  }\n}\n",paraId:28,tocIndex:14},{value:"@ant-design/x-card",paraId:29,tocIndex:15},{value:" supports both versions simultaneously:",paraId:29,tocIndex:15},{value:"import type { XAgentCommand_v0_8, XAgentCommand_v0_9 } from '@ant-design/x-card';\n\n// Auto-detect version and handle correctly\nconst commands: (XAgentCommand_v0_8 | XAgentCommand_v0_9)[] = [\n  // v0.8 message\n  {\n    updateComponents: {\n      /* ... */\n    },\n  },\n\n  // v0.9 message\n  {\n    version: 'v0.9',\n    createSurface: {\n      /* ... */\n    },\n  },\n];\n\n<XCard.Box commands={commands}>{/* ... */}</XCard.Box>;\n",paraId:30,tocIndex:15},{value:"The component automatically detects the protocol version based on the presence of the ",paraId:31,tocIndex:15},{value:"version",paraId:31,tocIndex:15},{value:" field and handles messages correctly.",paraId:31,tocIndex:15},{value:"@ant-design/x-card",paraId:32,tocIndex:16},{value:" fully implements the A2UI v0.9 core command system:",paraId:32,tocIndex:16},{value:"Creates a new UI container (Surface). Each Surface has its own independent component tree and data model.",paraId:33,tocIndex:17},{value:"{\n  version: 'v0.9',\n  createSurface: {\n    surfaceId: 'booking',  // Unique surface identifier\n    catalogId: 'https://example.com/catalogs/booking/v1/catalog.json'  // Component catalog\n  }\n}\n",paraId:34,tocIndex:17},{value:"Defines or updates UI components in a Surface using the adjacency list model.",paraId:35,tocIndex:18},{value:"{\n  version: 'v0.9',\n  updateComponents: {\n    surfaceId: 'booking',\n    components: [\n      { id: 'root', component: 'Column', children: ['header', 'guests-field', 'submit-btn'] },\n      { id: 'header', component: 'Text', text: 'Confirm Reservation', variant: 'h1' },\n      { id: 'guests-field', component: 'TextField', label: 'Guests', value: { path: '/reservation/guests' } },\n      {\n        id: 'submit-btn',\n        component: 'Button',\n        variant: 'primary',\n        child: 'submit-text',\n        action: {\n          event: { name: 'confirm', context: { details: { path: '/reservation' } } }\n        }\n      }\n    ]\n  }\n}\n",paraId:36,tocIndex:18},{value:"Updates the Surface's application state, triggering reactive UI updates.",paraId:37,tocIndex:19},{value:"{\n  version: 'v0.9',\n  updateDataModel: {\n    surfaceId: 'booking',\n    path: '/reservation',\n    value: {\n      datetime: '2025-12-16T19:00:00Z',\n      guests: 2\n    }\n  }\n}\n",paraId:38,tocIndex:19},{value:"Removes the specified Surface and all its components and data model.",paraId:39,tocIndex:20},{value:"{\n  version: 'v0.9',\n  deleteSurface: {\n    surfaceId: 'booking'\n  }\n}\n",paraId:40,tocIndex:20},{value:"A2UI separates UI structure from application state, enabling reactive updates through data binding.",paraId:41,tocIndex:21},{value:"Each Surface has an independent JSON data model:",paraId:42,tocIndex:22},{value:'{\n  "user": { "name": "Alice", "email": "alice@example.com" },\n  "reservation": { "datetime": "2025-12-16T19:00:00Z", "guests": 2 }\n}\n',paraId:43,tocIndex:22},{value:"Uses RFC 6901 standard JSON Pointer to access",paraId:44,tocIndex:23},{value:"/user/name",paraId:45,tocIndex:23},{value:" \u2192 ",paraId:45,tocIndex:23},{value:'"Alice"',paraId:45,tocIndex:23},{value:"/reservation/guests",paraId:45,tocIndex:23},{value:" \u2192 ",paraId:45,tocIndex:23},{value:"2",paraId:45,tocIndex:23},{value:"Component properties can use literal values or data binding:",paraId:46,tocIndex:24},{value:"// Literal (static)\n{ id: 'title', component: 'Text', text: 'Welcome' }\n\n// Path binding (dynamic)\n{ id: 'username', component: 'Text', text: { path: '/user/name' } }\n",paraId:47,tocIndex:24},{value:"When ",paraId:48,tocIndex:24},{value:"/user/name",paraId:48,tocIndex:24},{value:" changes from ",paraId:48,tocIndex:24},{value:'"Alice"',paraId:48,tocIndex:24},{value:" to ",paraId:48,tocIndex:24},{value:'"Bob"',paraId:48,tocIndex:24},{value:", the text updates automatically.",paraId:48,tocIndex:24},{value:"Interactive components can automatically update the data model:",paraId:49,tocIndex:25},{value:"{ id: 'name-input', component: 'TextField', value: { path: '/form/name' } }\n",paraId:50,tocIndex:25},{value:"User input automatically updates ",paraId:51,tocIndex:25},{value:"/form/name",paraId:51,tocIndex:25},{value:".",paraId:51,tocIndex:25},{value:"User interactions are passed back to the Agent via action events.",paraId:52,tocIndex:26},{value:"// Component definition\n{\n  id: 'submit-btn',\n  component: 'Button',\n  action: {\n    event: {\n      name: 'confirm_booking',\n      context: {\n        date: { path: '/reservation/datetime' },\n        guests: { path: '/reservation/guests' }\n      }\n    }\n  }\n}\n",paraId:53,tocIndex:26},{value:"When the user clicks the button, the client sends:",paraId:54,tocIndex:26},{value:"{\n  version: 'v0.9',\n  action: {\n    name: 'confirm_booking',\n    surfaceId: 'booking',\n    sourceComponentId: 'submit-btn',\n    timestamp: '2025-12-16T19:05:00Z',\n    context: { date: '2025-12-16T19:00:00Z', guests: 3 }\n  }\n}\n",paraId:55,tocIndex:26},{value:"The Catalog defines available components and their property schemas, ensuring type safety and validation.",paraId:56,tocIndex:27},{value:"registerCatalog(catalog);\n\n<XCard.Box\n  components={{\n    Text: MyTextComponent,\n    Button: MyButtonComponent,\n    TextField: MyTextFieldComponent,\n  }}\n>\n  {/* ... */}\n</XCard.Box>;\n",paraId:57,tocIndex:27},{value:"Users see the UI build up incrementally without waiting for the full response.",paraId:58,tocIndex:29},{value:"Uses a flat component list instead of a nested tree structure \u2014 LLM-friendly, supports incremental updates, and fault-tolerant.",paraId:59,tocIndex:30},{value:"Automatically validates component properties against the Catalog. Friendly errors in development, graceful degradation in production.",paraId:60,tocIndex:31},{value:"Full TypeScript type definitions:",paraId:61,tocIndex:32},{value:"import type {\n  XAgentCommand_v0_9,\n  XAgentCommand_v0_8,\n  ActionPayload,\n  Catalog,\n  CatalogComponent,\n} from '@ant-design/x-card';\n",paraId:62,tocIndex:32},{value:"npm install @ant-design/x-card\n# or\nyarn add @ant-design/x-card\n# or\npnpm add @ant-design/x-card\n",paraId:63,tocIndex:33},{value:"import { XCard, registerCatalog } from '@ant-design/x-card';\nimport type { XAgentCommand_v0_9, Catalog, ActionPayload } from '@ant-design/x-card';\n\nconst catalog: Catalog = {\n  catalogId: 'my-app-catalog',\n  components: {\n    Text: {\n      /* ... */\n    },\n    Button: {\n      /* ... */\n    },\n  },\n};\n\nregisterCatalog(catalog);\n\nconst commands: XAgentCommand_v0_9[] = [\n  { version: 'v0.9', createSurface: { surfaceId: 'booking', catalogId: 'my-app-catalog' } },\n  {\n    version: 'v0.9',\n    updateComponents: {\n      surfaceId: 'booking',\n      components: [\n        /* ... */\n      ],\n    },\n  },\n];\n\nfunction App() {\n  const handleAction = (payload: ActionPayload) => {\n    console.log('Action triggered:', payload.name, payload.context);\n  };\n\n  return (\n    <XCard.Box\n      commands={commands}\n      onAction={handleAction}\n      components={{ Text: MyTextComponent, Button: MyButtonComponent }}\n    >\n      <XCard.Card id=\"booking\" />\n    </XCard.Box>\n  );\n}\n",paraId:64,tocIndex:34},{value:"AI Assistant UIs",paraId:65,tocIndex:35},{value:": Let AI Agents dynamically generate forms, cards, and interactive interfaces",paraId:65,tocIndex:35},{value:"Smart Forms",paraId:65,tocIndex:35},{value:": Dynamically adjust form structure and validation rules based on user input",paraId:65,tocIndex:35},{value:"Data Visualization",paraId:65,tocIndex:35},{value:": Dynamically generate charts, lists, and data display components",paraId:65,tocIndex:35},{value:"Workflow Orchestration",paraId:65,tocIndex:35},{value:": Render different stage UIs based on business processes",paraId:65,tocIndex:35},{value:"Multi-turn Conversations",paraId:65,tocIndex:35},{value:": Embed dynamic interactive components in chat interfaces",paraId:65,tocIndex:35},{value:"Personalized UIs",paraId:65,tocIndex:35},{value:": Customize UI based on user preferences and usage scenarios",paraId:65,tocIndex:35},{value:"See ",paraId:66,tocIndex:36},{value:"A2UI v0.9",paraId:67,tocIndex:36},{value:" for the latest protocol spec and examples",paraId:66,tocIndex:36},{value:"Read the ",paraId:66,tocIndex:36},{value:"A2UI Official Docs",paraId:66,tocIndex:36},{value:" for protocol design philosophy",paraId:66,tocIndex:36},{value:"Browse ",paraId:66,tocIndex:36},{value:"Component Structure",paraId:66,tocIndex:36},{value:" to learn the adjacency list model",paraId:66,tocIndex:36},{value:"Reference ",paraId:66,tocIndex:36},{value:"Data Binding",paraId:66,tocIndex:36},{value:" to master reactive updates",paraId:66,tocIndex:36}];}}]);